module top_module(
    input  data_in_0,
    input  data_in_1,
    input  ctrl,
    output data_out
);// Voltage supply signals
    supply1 VPWR;
    supply0 VGND;
    supply1 VPB ;
    supply0 VNB ;

    wire inverted_data_out = (ctrl == 0) ? data_in_0 : data_in_1;
    assign data_out = inverted_data_out;

endmodule
